 1→export const PHASE_VIEW = {
 2→  ALL: 'all',
 3→  SINGLE: 'single',
 4→  CUMULATIVE: 'cumulative',
 5→};
 6→
 7→const PHASE_ASSIGNABLE_ARRAYS = [
 8→  'walls', 'doors', 'windows', 'columns', 'beams', 'slabs',
 9→  'stairs', 'landings', 'fixtures', 'rooms', 'railings',
10→];
11→
12→export function isObjectVisibleInPhase(obj, phases, activePhaseId, phaseViewMode) {
13→  if (phaseViewMode === PHASE_VIEW.ALL) return true;
14→  if (!obj.phaseId) return true;
15→  if (!activePhaseId) return true;
16→
17→  if (phaseViewMode === PHASE_VIEW.SINGLE) {
18→    return obj.phaseId === activePhaseId;
19→  }
20→
21→  if (phaseViewMode === PHASE_VIEW.CUMULATIVE) {
22→    const activePhase = phases.find(p => p.id === activePhaseId);
23→    const objPhase = phases.find(p => p.id === obj.phaseId);
24→    if (!activePhase || !objPhase) return true;
25→    return objPhase.order <= activePhase.order;
26→  }
27→
28→  return true;
29→}
30→
31→export function filterFloorByPhase(floor, phases, activePhaseId, phaseViewMode) {
32→  if (!floor) return floor;
33→  if (phaseViewMode === PHASE_VIEW.ALL) return floor;
34→  if (!activePhaseId) return floor;
35→
36→  const isVisible = (obj) => isObjectVisibleInPhase(obj, phases, activePhaseId, phaseViewMode);
37→
38→  const filtered = { ...floor };
39→
40→  for (const key of PHASE_ASSIGNABLE_ARRAYS) {
41→    const arr = floor[key];
42→    if (!arr) continue;
43→    filtered[key] = arr.filter(isVisible);
44→  }
45→
46→  // Also filter doors/windows whose parent wall was filtered out
47→  const visibleWallIds = new Set(filtered.walls.map(w => w.id));
48→  filtered.doors = filtered.doors.filter(d => visibleWallIds.has(d.wallId));
49→  filtered.windows = filtered.windows.filter(w => visibleWallIds.has(w.wallId));
50→
51→  return filtered;
52→}
53→
54→export function filterProjectByPhase(project, activePhaseId, phaseViewMode) {
55→  if (!project) return project;
56→  if (phaseViewMode === PHASE_VIEW.ALL) return project;
57→  if (!activePhaseId) return project;
58→
59→  const phases = project.phases || [];
60→  return {
61→    ...project,
62→    floors: project.floors.map(floor => filterFloorByPhase(floor, phases, activePhaseId, phaseViewMode)),
63→  };
64→}
