 71→export default function Sidebar() {
 72→  const { project, dispatch, duplicateFloor } = useProject();
 73→  const { activeFloorId, activeSheetId, selectedId, workspaceMode, activePhaseId, phaseViewMode, dispatch: editorDispatch } = useEditor();
 74→  const orderedFloors = getOrderedFloors(project);
 75→  const orderedPhases = getOrderedPhases(project);
 76→  const floor = orderedFloors.find((entry) => entry.id === activeFloorId) || null;
 77→  const [collapsedSections, setCollapsedSections] = useState({
 78→    floors: false,
 79→    sheets: false,
 80→    phases: false,
 81→    slabs: false,
 82→    walls: false,
 83→    annotations: false,
 84→    beams: false,
 85→    stairs: false,
 86→    landings: false,
 87→    doors: false,
 88→    windows: false,
 89→    columns: false,
 90→    rooms: false,
 91→  });
 92→
 93→  const selectObject = (id, type) => {
 94→    editorDispatch({ type: 'SELECT_OBJECT', id, objectType: type });
 95→  };
 96→
 97→  const selectFloor = (floorId) => {
 98→    editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
 99→    editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId });
100→    editorDispatch({ type: 'SELECT_OBJECT', id: floorId, objectType: 'floor' });
101→  };
102→
103→  const setActiveFloor = (floorId) => {
104→    editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId });
105→  };
106→
107→  const addFloor = () => {
108→    const nextFloor = createFloorAboveHighest(project.floors || []);
109→    dispatch({ type: 'FLOOR_ADD', floor: nextFloor });
110→    selectFloor(nextFloor.id);
111→  };
112→
113→  const handleDuplicateFloor = (floorToDuplicate) => {
114→    const duplicatedFloor = duplicateFloor(floorToDuplicate.id);
115→    if (!duplicatedFloor) return;
116→
117→    dispatch({ type: 'FLOOR_DUPLICATE', floor: duplicatedFloor });
118→    selectFloor(duplicatedFloor.id);
119→  };
120→
121→  const handleDeleteFloor = (floorToDelete) => {
122→    if ((project.floors || []).length <= 1) return;
123→
124→    const confirmed = window.confirm(`Delete "${floorToDelete.name}"?`);
125→    if (!confirmed) return;
126→
127→    const remainingFloors = orderedFloors.filter((entry) => entry.id !== floorToDelete.id);
128→    const fallbackFloor = remainingFloors[0] || null;
129→
130→    dispatch({
131→      type: 'FLOOR_DELETE',
132→      floorId: floorToDelete.id,
133→      fallbackFloorId: fallbackFloor?.id ?? null,
134→    });
135→
136→    if (floorToDelete.id === activeFloorId && fallbackFloor) {
137→      if (workspaceMode === 'model') {
138→        selectFloor(fallbackFloor.id);
139→      } else {
140→        setActiveFloor(fallbackFloor.id);
141→      }
142→    }
143→  };
144→
145→  const addPhase = () => {
146→    const nextOrder = getNextPhaseOrder(project.phases || []);
147→    const color = PHASE_COLORS[nextOrder % PHASE_COLORS.length];
148→    const phase = createPhase(`Phase ${nextOrder + 1}`, nextOrder, color);
149→    dispatch({ type: 'PHASE_ADD', phase });
150→    editorDispatch({ type: 'SET_ACTIVE_PHASE', phaseId: phase.id });
151→    editorDispatch({ type: 'SELECT_OBJECT', id: phase.id, objectType: 'phase' });
152→  };
153→
154→  const selectPhase = (phaseId) => {
155→    editorDispatch({ type: 'SET_ACTIVE_PHASE', phaseId });
156→    editorDispatch({ type: 'SELECT_OBJECT', id: phaseId, objectType: 'phase' });
157→  };
158→
159→  const handleDeletePhase = (phase) => {
160→    if (!window.confirm(`Delete phase "${phase.name}"?`)) return;
161→    dispatch({ type: 'PHASE_DELETE', phaseId: phase.id });
162→    if (activePhaseId === phase.id) {
163→      editorDispatch({ type: 'SET_ACTIVE_PHASE', phaseId: null });
164→      editorDispatch({ type: 'SET_PHASE_VIEW_MODE', mode: 'all' });
165→    }
166→    editorDispatch({ type: 'DESELECT' });
167→  };
168→
169→  const handleMovePhase = (phase, direction) => {
170→    const newOrder = phase.order + direction;
171→    const reordered = reorderPhases(project.phases || [], phase.id, newOrder);
172→    dispatch({ type: 'PHASE_REORDER', phases: reordered });
173→  };
174→
175→  const addSheet = () => {
176→    const nextIndex = (project.sheets || []).length + 1;
177→    const sheet = createSheet(`Sheet ${nextIndex}`, {
178→      drawingName: `Drawing ${nextIndex}`,
179→      number: `A${String(nextIndex).padStart(2, '0')}`,
180→    });
181→    dispatch({ type: 'SHEET_ADD', sheet });
182→    editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheet.id });
183→    editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' });
184→    editorDispatch({ type: 'SELECT_OBJECT', id: sheet.id, objectType: 'sheet' });
185→  };
186→
187→  const toggleSection = (sectionKey) => {
188→    setCollapsedSections(current => ({
189→      ...current,
190→      [sectionKey]: !current[sectionKey],
191→    }));
192→  };
193→
194→  return (
195→    <div className={styles.sidebar}>
196→      <Section title="Project" collapsible={false}>
197→        <input
198→          className={styles.projectName}
199→          value={project.name}
200→          onChange={(e) => dispatch({ type: 'PROJECT_SET_NAME', name: e.target.value })}
201→        />
202→      </Section>
203→
204→      <Section
205→        title="Floors"
206→        count={orderedFloors.length}
207→        collapsed={collapsedSections.floors}
208→        onToggle={() => toggleSection('floors')}
209→        action={
210→          <button type="button" className={styles.sectionAddBtn} onClick={addFloor} title="Add Floor">+</button>
211→        }
212→      >
213→        {orderedFloors.map((entry) => (
214→          <div
215→            key={entry.id}
216→            className={`${styles.floorCard} ${entry.id === activeFloorId ? styles.floorCardActive : ''}`}
217→          >
218→            <button
219→              type="button"
220→              className={styles.floorButton}
221→              onClick={() => selectFloor(entry.id)}
222→            >
223→              <span className={styles.floorName}>{entry.name}</span>
224→              <span className={styles.floorMeta}>
225→                L{getFloorLevelIndex(entry)} · {Math.round(getFloorElevation(entry))} mm
226→              </span>
227→            </button>
228→            <div className={styles.floorActions}>
229→              <button
230→                type="button"
231→                className={styles.floorActionBtn}
232→                onClick={() => handleDuplicateFloor(entry)}
233→                title={`Duplicate ${entry.name}`}
234→              >
235→                <DuplicateIcon />
236→              </button>
237→              <button
238→                type="button"
239→                className={`${styles.floorActionBtn} ${styles.floorActionDanger}`}
240→                onClick={() => handleDeleteFloor(entry)}
241→                title={`Delete ${entry.name}`}
242→                disabled={orderedFloors.length <= 1}
243→              >
244→                <TrashIcon />
245→              </button>
246→            </div>
247→          </div>
248→        ))}
249→      </Section>
250→
251→      <Section
252→        title="Sheets"
253→        count={(project.sheets || []).length}
254→        collapsed={collapsedSections.sheets}
255→        onToggle={() => toggleSection('sheets')}
256→        action={
257→          <button type="button" className={styles.sectionAddBtn} onClick={addSheet} title="Add Sheet">+</button>
258→        }
259→      >
260→        {(project.sheets || []).map((sheet, index) => (
261→          <div
262→            key={sheet.id}
263→            className={`${styles.item} ${workspaceMode === 'sheet' && activeSheetId === sheet.id ? styles.itemSelected : ''}`}
264→            onClick={() => {
265→              editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheet.id });
266→              editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' });
267→              editorDispatch({ type: 'SELECT_OBJECT', id: sheet.id, objectType: 'sheet' });
268→            }}
269→          >
270→            {getSheetDisplayLabel(sheet, index)}
271→          </div>
272→        ))}
273→      </Section>
274→
275→      <Section
276→        title="Phases"
277→        count={orderedPhases.length}
278→        collapsed={collapsedSections.phases}
279→        onToggle={() => toggleSection('phases')}
280→        action={
281→          <button type="button" className={styles.sectionAddBtn} onClick={addPhase} title="Add Phase">+</button>
282→        }
283→      >
284→        <div className={styles.phaseViewControl} role="group" aria-label="Phase view mode">
285→          {['all', 'single', 'cumulative'].map(mode => (
286→            <button
287→              key={mode}
288→              type="button"
289→              className={phaseViewMode === mode ? styles.phaseViewBtnActive : styles.phaseViewBtn}
290→              onClick={() => editorDispatch({ type: 'SET_PHASE_VIEW_MODE', mode })}
291→            >
292→              {mode.charAt(0).toUpperCase() + mode.slice(1)}
293→            </button>
